CREATE TABLE IF NOT EXISTS bpm_oa_document (id bigint NOT NULL AUTO_INCREMENT,owner_user_id bigint NOT NULL,parent_id bigint DEFAULT NULL,name varchar(200) NOT NULL,description varchar(2000),visibility tinyint NOT NULL DEFAULT 0,status tinyint NOT NULL DEFAULT 0,current_version int NOT NULL DEFAULT 0,creator varchar(64),create_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,updater varchar(64),update_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,deleted bit(1) NOT NULL DEFAULT b'0',tenant_id bigint NOT NULL DEFAULT 0,PRIMARY KEY(id),KEY idx_doc_parent(tenant_id,parent_id,status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS bpm_oa_document_member (id bigint NOT NULL AUTO_INCREMENT,document_id bigint NOT NULL,user_id bigint NOT NULL,permission tinyint NOT NULL DEFAULT 1,creator varchar(64),create_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,updater varchar(64),update_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,deleted bit(1) NOT NULL DEFAULT b'0',tenant_id bigint NOT NULL DEFAULT 0,PRIMARY KEY(id),UNIQUE KEY uk_doc_user(document_id,user_id,tenant_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS bpm_oa_document_version (id bigint NOT NULL AUTO_INCREMENT,document_id bigint NOT NULL,version int NOT NULL,file_id bigint NOT NULL,change_summary varchar(1000),created_by bigint NOT NULL,creator varchar(64),create_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,updater varchar(64),update_time datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,deleted bit(1) NOT NULL DEFAULT b'0',tenant_id bigint NOT NULL DEFAULT 0,PRIMARY KEY(id),UNIQUE KEY uk_doc_version(document_id,version,tenant_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
